import java.util.HashSet;
import java.util.Set;

public class Solution {
    public int distinctIntegersAfterReversingAndAdding(int[] nums) {
        Set<Integer> distinct = new HashSet<>();

        // Separate loop for adding numbers to the set
        for (int num : nums) {
            distinct.add(num);

            // Extracted operation into a separate standalone loop
            reverseAndAddToSet(distinct, num);
        }

        return distinct.size();
    }

    private void reverseAndAddToSet(Set<Integer> distinct, int num) {
        int reversed = 0;
        while (num > 0) {
            reversed = reversed * 10 + num % 10;
            num /= 10;
        }

        // Add the reversed number to the set
        distinct.add(reversed);
    }

}

