    public int minValidSubarrays(int[] nums) {
        int count = 0;
        while(nums.length > 0) {
            if (!hasGCDGreaterThanOne(nums)) {
                break;
            }
            removeLastElementIfNoCommonFactor(nums);
            count++;
        }
        return (count > 0) ? count : -1;
    }

    private boolean hasGCDGreaterThanOne(int[] nums) {
        for (int i = 0; i < nums.length - 1; i++) {
            if (gcd(nums[i], nums[nums.length - 1]) > 1) {
                return true;
            }
        }
        return false;
    }

    private void removeLastElementIfNoCommonFactor(int[] nums) {
        for (int i = 0; i < nums.length - 1; i++) {
            if (gcd(nums[i], nums[nums.length - 1]) > 1) {
                break;
            }
        }
        int length = nums.length;
        nums = Arrays.copyOf(nums, length - 1);
    }

    private int gcd(int a, int b) {
        while (b != 0) {
            int temp = a % b;
            a = b;
            b = temp;
        }
        return a;
    }
}

