import java.util.List;


public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode() {}
    TreeNode(int val) { this.val = val; }
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

public class Solution {
    public 


    public List<List<Integer>> findMinMax(TreeNode root, int[] queries) {
        if (root == null) {
            return new ArrayList<>();
        }

        List<List<Integer>> ans = new ArrayList<>();
        for (int query : queries) {
            TreeNode node = root;
            List<Integer> currentList = Arrays.asList(-1, -1);
            while (node != null) {
                if (node.val < query) {
                    currentList.set(0, node.val);
                    node = node.right;
                } else {
                    currentList.set(1, node.val);
                    if (node.val == query) {
                        currentList.set(0, query);
                        break;
                    }
                    node = node.left;
                }
            }
            ans.add(currentList);
        }
        return ans;
    }
}

