public class Solution {

    public List<List<Integer>> findMinMax(TreeNode root, int[] queries) {
        if (root == null) {
            return new ArrayList<>();
        }

        List<List<Integer>> ans = new ArrayList<>();
        for (int query : queries) {
            TreeNode node = root;
            List<Integer> currentList = Arrays.asList(-1, -1);
            while (node != null) {
                if (node.val < query) {
                    currentList.set(0, node.val);
                    node = node.right;
                } else {
                    currentList.set(1, node.val);
                    if (node.val == query) {
                        currentList.set(0, query);
                        break;
                    }
                    node = node.left;
                }
            }
            ans.add(currentList);
        }
        return ans;
    }

    private int findLeftMin(TreeNode root) {
        int leftMin = Integer.MAX_VALUE;
        while (root != null && root.val < leftMin) {
            leftMin = Math.min(leftMin, root.val);
            root = root.left;
        }
        return leftMin;
    }

    private int findRightMax(TreeNode root) {
        int rightMax = Integer.MIN_VALUE;
        while (root != null && root.val > rightMax) {
            rightMax = Math.max(rightMax, root.val);
            root = root.right;
        }
        return rightMax;
    }
}

