    public int maxCapturedForts(int[] forts) {
        int n = forts.length;
        int maxCapture = 0;
        for(int i = 0; i < n; i++) {
            if(forts[i] == 1) {
                for(int j = i + 1; j < n; j++) {
                    if(forts[j] != -1) {
                        int capture = 0;
                        for(int k = i + 1; k < j; k++) {
