    public int minCostToEqualBaskets(int[] basket1, int[] basket2) {
        Map<Integer, Integer> diffCount = new HashMap<>();
        for (int i = 0; i < basket1.length; i++) {
            diffCount.put(basket1[i] - basket2[i], diffCount.getOrDefault(basket1[i] - basket2[i], 0) + 1);
        }

        int minCost = Integer.MAX_VALUE, cost = 0;
        for (Map.Entry<Integer, Integer> entry : diffCount.entrySet()) {
            if (entry.getValue().equals(diffCount.get(-entry.getKey()))) {
                cost = 0;
                for (int i = 0; i < basket1.length; i++) {
                    if (basket1[i] - basket2[i] == entry.getKey()) {
                        cost += Math.min(basket1[i], basket2[i]);
                    }
                }
                minCost = Math.min(minCost, cost);
            }
        }

        return minCost == Integer.MAX_VALUE ? -1 : minCost / 2;
    }
}

