public class Solution {
    public int concatenationValue(int[] nums) {
        int value = 0;
        int n = nums.length;
        for (int i = 0; i < n; i += 2) {
            if (i == n - 1 - i) {
                value += nums[i];
            } else {
                value += Integer.parseInt(String.valueOf(nums[i]) + String.valueOf(nums[n - 1 - i]));
            }
        }
        return value;
    }
}

