        Arrays.sort(nums);
        return IntStream.rangeClosed(1, Integer.MAX_VALUE)
                .filter(i -> !Arrays.stream(nums).anyMatch(n -> i % n == 0))
                .findFirst()
                .orElse(Integer.MAX_VALUE - 1);
    }
}

