    public boolean isValidMove(int i, int j, int k, int n) {
        return (i + 1 < n && j + 2 < n && k == n * (i + 1) + (j + 2)) ||
               (i + 1 < n && j - 2 >= 0 && k == n * (i + 1) + (j - 2)) ||
               (i + 2 < n && j + 1 < n && k == n * (i + 2) + (j + 1)) ||
               (i + 2 < n && j - 1 >= 0 && k == n * (i + 2) + (j - 1));
    }

    public boolean validPath(int[][] grid) {
        int n = grid.length;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                int k = grid[i][j];
                if (k != n * n - 1 && !isValidMove(i, j, k + 1, n)) {
                    return false;
                }
            }
        }
        return true;
    }
}

