import java.util.*;

public class Solution {
    public int minEdgesToCollectCoins(int[] coins, int[][] edges) {
        int n = coins.length;
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (int[] edge : edges) {
            adj.get(edge[0]).add(edge[1]);
            adj.get(edge[1]).add(edge[0]);
        }
        return dfs(adj, coins, 0, -1)[1] / 2;
    }

    private int[] dfs(List<List<Integer>> adj, int[] coins, int node, int parent) {
        int sum = coins[node], distance = 0;
        for (int neighbor : adj.get(node)) {
            if (neighbor != parent) {
                int[] result = dfs(adj, coins, neighbor, node);
                sum += result[0];
                distance += 2 * result[0] + result[1];
            }
        }
        return new int[] {sum, distance};
    }
}

